from flask import Flask, request, redirect, url_for, render_template_string
import os
import smtplib
from itsdangerous import URLSafeTimedSerializer

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Dummy database for demonstration purposes
users_db = {
    'user1@example.com': {'mfa_enabled': False}
}

serializer = URLSafeTimedSerializer(app.secret_key)

def send_reset_email(email):
    token = serializer.dumps(email, salt='reset-salt')
    reset_url = url_for('reset_mfa', token=token, _external=True)
    message = f'Click the following link to reset your MFA: {reset_url}'
    # Send email logic here
    print(f"Sending reset email to {email}: {message}")

@app.route('/enable-mfa')
def enable_mfa():
    email = request.args.get('email')
    if email in users_db:
        users_db[email]['mfa_enabled'] = True
        return f"MFA enabled for {email}"
    return "User not found", 404

@app.route('/disable-mfa')
def disable_mfa():
    email = request.args.get('email')
    if email in users_db:
        users_db[email]['mfa_enabled'] = False
        return f"MFA disabled for {email}"
    return "User not found", 404

@app.route('/reset-mfa', methods=['GET'])
def reset_mfa():
    token = request.args.get('token')
    try:
        email = serializer.loads(token, salt='reset-salt', max_age=3600)
        if email in users_db:
            users_db[email]['mfa_enabled'] = False
            return "MFA disabled. Please log in with your password."
        else:
            return "User not found", 404
    except Exception as e:
        return str(e), 400

@app.route('/send-reset-link', methods=['POST'])
def send_reset_link():
    email = request.form.get('email')
    if email in users_db:
        send_reset_email(email)
        return "Reset link sent to your email."
    else:
        return "User not found", 404

if __name__ == '__main__':
    app.run(debug=True)